def parse_duration(s):
    if not s:
        raise ValueError("Input string cannot be empty")

    units = {'h': 60, 'm': 1}
    parts = s.strip().lower().split(' ')
    if len(parts) > 2 or (len(parts) == 2 and any(p not in units for p in parts)):
        raise ValueError("Malformed input")

    total_minutes = 0
    for part in parts:
        if part.endswith('h'):
            total_minutes += int(part[:-1]) * units['h']
        elif part.endswith('m'):
            total_minutes += int(part[:-1]) * units['m']

    return total_minutes
```

